class Solution:
    def canMeasureWater(self, x: int, y: int, target: int) -> bool:
        if x + y < target:
            return False
        return target % self.gcd(x, y) == 0

    def gcd(self, a: int, b: int) -> int:
        while b:
            a, b = b, a % b
        return a
```
